//-------------------------------------------------------------------------
// Constructor
//-------------------------------------------------------------------------
MRFTyreDepthAnsysCmd::MRFTyreDepthAnsysCmd() :
CATMmrStateCommand ("MRFTyreDepthAnsysCmd", CATDlgEngOneShot, CATCommandModeShared)
//  Valid states are CATDlgEngOneShot and CATDlgEngRepeat
, _pMRFTyreDepthAnsysCmdDlg(NULL)
, _pPathElementAgentForSurface(NULL)
, _pDialogAgentForSourceSurface(NULL)
, _pDialogAgentForBaldSurface(NULL)
, _pHSO(NULL)
, _pISO(NULL)
, _pEditor(NULL)
, _pPathElementForSourceSurface(NULL)
, _pPathElementForBaldSurface(NULL)
, _pPathElementForAxis(NULL)
, _spSourceSurface(NULL_var)
, _spBaldSurface(NULL_var)
, _pComputePointDistance(NULL)
, _pFileDialog(NULL)
{

	_pEditor = CATFrmEditor::GetCurrentEditor();
	if (NULL != _pEditor)
	{
		_pHSO = _pEditor->GetHSO();
		_pISO = _pEditor->GetISO();
	}

	_pComputePointDistance = new ComputeGridPointDistance();
	_bRunCompute = CATFalse;
}

//-------------------------------------------------------------------------
// Destructor
//-------------------------------------------------------------------------
MRFTyreDepthAnsysCmd::~MRFTyreDepthAnsysCmd()
{
	if (_pMRFTyreDepthAnsysCmdDlg)
		_pMRFTyreDepthAnsysCmdDlg->RequestDelayedDestruction(); _pMRFTyreDepthAnsysCmdDlg  = NULL;

	if(_pPathElementAgentForSurface)
		_pPathElementAgentForSurface->RequestDelayedDestruction(); _pPathElementAgentForSurface = NULL;

	if(_pDialogAgentForSourceSurface)
		_pDialogAgentForSourceSurface->RequestDelayedDestruction(); _pDialogAgentForSourceSurface = NULL;
	
	if(_pDialogAgentForBaldSurface)
		_pDialogAgentForBaldSurface->RequestDelayedDestruction(); _pDialogAgentForBaldSurface = NULL;
	
	if (_pEditor != NULL)
	{
		if (NULL != _pHSO && !_pHSO->IsNull())
		{
			_pHSO->Empty();
			_pHSO = NULL;
		}

		if (NULL != _pISO && !_pISO->IsNull())
		{
			_pISO->Empty();
			_pISO = NULL;
		}

		_pEditor = NULL;
	}		
	
	if (_pPathElementForSourceSurface)
		 _pPathElementForSourceSurface = NULL;

	if (_pPathElementForBaldSurface)
		 _pPathElementForBaldSurface = NULL;

	if (_pPathElementForAxis)
		_pPathElementForAxis = NULL;

	_spSourceSurface = NULL_var;
	_spBaldSurface = NULL_var;

	if (_pComputePointDistance)
		_pComputePointDistance->Release(); _pComputePointDistance = NULL;

	if (_pFileDialog != NULL)
		_pFileDialog = NULL;	
}


//-------------------------------------------------------------------------
// BuildGraph()
//-------------------------------------------------------------------------
void MRFTyreDepthAnsysCmd::BuildGraph()
{

	_pMRFTyreDepthAnsysCmdDlg = new MRFDepthAnsysCmdDlg();
	if (!!_pMRFTyreDepthAnsysCmdDlg)
	{
		_pMRFTyreDepthAnsysCmdDlg->Build();
		_pMRFTyreDepthAnsysCmdDlg->SetVisibility(CATDlgShow);

		AddAnalyseNotificationCB(_pMRFTyreDepthAnsysCmdDlg, _pMRFTyreDepthAnsysCmdDlg->GetDiaOKNotification(), (CATCommandMethod)& MRFTyreDepthAnsysCmd::OnOK, NULL);
	//	AddAnalyseNotificationCB(_pMRFTyreDepthAnsysCmdDlg, _pMRFTyreDepthAnsysCmdDlg->GetDiaAPPLYNotification(), (CATCommandMethod)& MRFTyreDepthAnsysCmd::OnApply, NULL);
		AddAnalyseNotificationCB(_pMRFTyreDepthAnsysCmdDlg, _pMRFTyreDepthAnsysCmdDlg->GetDiaCANCELNotification(), (CATCommandMethod)& MRFTyreDepthAnsysCmd::OnClose, NULL);
		AddAnalyseNotificationCB(_pMRFTyreDepthAnsysCmdDlg, _pMRFTyreDepthAnsysCmdDlg->GetWindCloseNotification(), (CATCommandMethod)& MRFTyreDepthAnsysCmd::OnClose, NULL);

		CATListOfCATString ListSurfaces = GetSurfaceSelectorTypes();

		_pPathElementAgentForSurface = new CATPathElementAgent("RefSurfacePathElementAgent");
		if (_pPathElementAgentForSurface)
		{
			_pPathElementAgentForSurface->SetOrderedTypeList(ListSurfaces);
			_pPathElementAgentForSurface->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);
		}

		CATDlgSelectorList* pSelectorListSourceSurf = _pMRFTyreDepthAnsysCmdDlg->GetSelectorListSourceSurf();
		_pDialogAgentForSourceSurface = new CATDialogAgent("RefSurfaceDialogAgent");
		if (_pDialogAgentForSourceSurface && NULL != pSelectorListSourceSurf)
		{
			_pDialogAgentForSourceSurface->AcceptOnNotify(pSelectorListSourceSurf, pSelectorListSourceSurf->GetListSelectNotification());
			_pMRFTyreDepthAnsysCmdDlg->SetFocusOnSelectorList(pSelectorListSourceSurf);
		}

		CATDlgSelectorList* pSelectorListBaldSurf = _pMRFTyreDepthAnsysCmdDlg->GetSelectorListBaldSurf();
		_pDialogAgentForBaldSurface = new CATDialogAgent("BaldSurfaceDialogAgent");
		if (_pDialogAgentForBaldSurface && NULL != pSelectorListBaldSurf)
		{
			_pDialogAgentForBaldSurface->AcceptOnNotify(pSelectorListBaldSurf, pSelectorListBaldSurf->GetListSelectNotification());
		}

		CATDlgContextualMenu* contextMenuClearSelectionSourceSurf = _pMRFTyreDepthAnsysCmdDlg->GetCustomContextualMenuOfSelectorListSourceSurface();
		if (contextMenuClearSelectionSourceSurf)
		{
			AddAnalyseNotificationCB(contextMenuClearSelectionSourceSurf, contextMenuClearSelectionSourceSurf->GetVisibilityNotification(), (CATCommandMethod)&MRFTyreDepthAnsysCmd::OnContextMenuSourceSurfaceSelected, "FromSourceSurfaceSelectorList");
		}

		CATDlgContextualMenu* contextMenuClearSelectionBaldSurf = _pMRFTyreDepthAnsysCmdDlg->GetCustomContextualMenuOfSelectorListBaldSurface();
		if (contextMenuClearSelectionBaldSurf)
		{
			AddAnalyseNotificationCB(contextMenuClearSelectionBaldSurf, contextMenuClearSelectionBaldSurf->GetVisibilityNotification(), (CATCommandMethod)&MRFTyreDepthAnsysCmd::OnContextMenuSourceSurfaceSelected, "FromBaldSurfaceSelectorList");
		}

		CATDlgCheckButton* pCheckButtonTyreDirection = _pMRFTyreDepthAnsysCmdDlg->GetCheckButtonTyreDirection();
		if (pCheckButtonTyreDirection)
		{
			AddAnalyseNotificationCB(pCheckButtonTyreDirection, pCheckButtonTyreDirection->GetChkBModifyNotification(), (CATCommandMethod)&MRFTyreDepthAnsysCmd::OnCheckButtonModified, NULL);
		}

		CATDlgPushButton* pPushButtonReverseDirection = _pMRFTyreDepthAnsysCmdDlg->GetPushButtonReverseDirection();
		if (pPushButtonReverseDirection)
		{
			AddAnalyseNotificationCB(pPushButtonReverseDirection, pPushButtonReverseDirection->GetPushBActivateNotification(), (CATCommandMethod)& MRFTyreDepthAnsysCmd::OnPushButtonReverseDirectionClicked, NULL);
		}

		CATDlgSpinner* pOnSpinnerLateral = _pMRFTyreDepthAnsysCmdDlg->GetEditorGridSpacingLateral();
		if (pOnSpinnerLateral)
		{
			AddAnalyseNotificationCB(pOnSpinnerLateral, pOnSpinnerLateral->GetSpinnerModifyNotification(), (CATCommandMethod)& MRFTyreDepthAnsysCmd::ResetValues, NULL);
		}

		CATDlgSpinner* pOnSpinnerCircumf = _pMRFTyreDepthAnsysCmdDlg->GetEditorGridSpacingCircumf();
		if (pOnSpinnerCircumf)
		{
			AddAnalyseNotificationCB(pOnSpinnerCircumf, pOnSpinnerCircumf->GetSpinnerModifyNotification(), (CATCommandMethod)& MRFTyreDepthAnsysCmd::ResetValues, NULL);
		}

		CATDlgCheckButton* pCheckButtonPreview = _pMRFTyreDepthAnsysCmdDlg->GetCheckButtonPreview();
		if (pCheckButtonPreview)
		{
			AddAnalyseNotificationCB(pCheckButtonPreview, pCheckButtonPreview->GetChkBModifyNotification(), (CATCommandMethod)& MRFTyreDepthAnsysCmd::DisplayPreview, NULL);
		}

		CATDialogState *initialState = GetInitialState("InitialState");
		initialState->AddDialogAgent(_pPathElementAgentForSurface);
		initialState->AddDialogAgent(_pDialogAgentForSourceSurface);
		initialState->AddDialogAgent(_pDialogAgentForBaldSurface);

		CATDialogState *BaldSurfSelectionState = AddDialogState("BaldSurfSelectionState");
		BaldSurfSelectionState->AddDialogAgent(_pPathElementAgentForSurface);
		BaldSurfSelectionState->AddDialogAgent(_pDialogAgentForSourceSurface);
		BaldSurfSelectionState->AddDialogAgent(_pDialogAgentForBaldSurface);

		CATDialogState *pComputeState = AddDialogState("ComputeDepthState");
		pComputeState->AddDialogAgent(_pDialogAgentForSourceSurface);
		pComputeState->AddDialogAgent(_pDialogAgentForBaldSurface);
		pComputeState->AddDialogAgent(_pPathElementAgentForSurface);

		AddTransition(initialState, initialState, IsOutputSetCondition(_pDialogAgentForSourceSurface), Action((ActionMethod)&MRFTyreDepthAnsysCmd::OnSourceSurfaceSelectorListSelected));
		AddTransition(BaldSurfSelectionState, initialState, IsOutputSetCondition(_pDialogAgentForSourceSurface), Action((ActionMethod)&MRFTyreDepthAnsysCmd::OnSourceSurfaceSelectorListSelected));
		AddTransition(pComputeState, initialState, IsOutputSetCondition(_pDialogAgentForSourceSurface), Action((ActionMethod)&MRFTyreDepthAnsysCmd::OnSourceSurfaceSelectorListSelected));

		AddTransition(initialState, BaldSurfSelectionState, IsOutputSetCondition(_pDialogAgentForBaldSurface), Action((ActionMethod)&MRFTyreDepthAnsysCmd::OnBaldSurfaceSelectorListSelected));
		AddTransition(BaldSurfSelectionState, BaldSurfSelectionState, IsOutputSetCondition(_pDialogAgentForBaldSurface), Action((ActionMethod)&MRFTyreDepthAnsysCmd::OnBaldSurfaceSelectorListSelected));
		AddTransition(pComputeState, BaldSurfSelectionState, IsOutputSetCondition(_pDialogAgentForBaldSurface), Action((ActionMethod)&MRFTyreDepthAnsysCmd::OnBaldSurfaceSelectorListSelected));

		AddTransition(initialState, BaldSurfSelectionState, IsOutputSetCondition(_pPathElementAgentForSurface), Action((ActionMethod)&MRFTyreDepthAnsysCmd::OnSourceSurfaceSelected));
		AddTransition(BaldSurfSelectionState, pComputeState, IsOutputSetCondition(_pPathElementAgentForSurface), Action((ActionMethod)&MRFTyreDepthAnsysCmd::OnBaldSurfaceSelected));

		
		
	}
}

