//---------------------Function to set focus and add source surface pathelement to HSo when OnSourceSurfaceSelectorList selected STARTS---------------------------//
CATBoolean MRFTyreDepthAnsysCmd::OnSourceSurfaceSelectorListSelected(void * data)
{
	if (!!_pDialogAgentForSourceSurface)
		_pDialogAgentForSourceSurface->InitializeAcquisition();

	this->_ActiveListSelected = activeSelection::SourceSurface;

	if (NULL != _pHSO && 0 == _pHSO->IsMember(_pPathElementForSourceSurface))
	{
		_pHSO->Empty();
		_pHSO->AddElement(_pPathElementForSourceSurface);
		if (NULL != _pPathElementForAxis)
		{
			_pHSO->AddElement(_pPathElementForAxis);
		}
	}

	CATUnicodeString strString = "Select Source Surface";
	if (!!_pMRFTyreDepthAnsysCmdDlg)
	{
		_pMRFTyreDepthAnsysCmdDlg->SetStatusBarText(strString);
		ClearAllSelections();

		CATDlgSelectorList* pSingleEdgeRefEdgeSelector = NULL;
		pSingleEdgeRefEdgeSelector = _pMRFTyreDepthAnsysCmdDlg->GetSelectorListSourceSurf();
		if (NULL != pSingleEdgeRefEdgeSelector)
		{
			_pMRFTyreDepthAnsysCmdDlg->SetFocusOnSelectorList(pSingleEdgeRefEdgeSelector);
		}
	}
	return TRUE;
}
//---------------------Function to set focus and add source surface pathelement to HSo when OnSourceSurfaceSelectorList selected ENDS---------------------------//

//---------------------Function to set focus and add bald surface pathelement to HSo when OnBaldSurfaceSelectorList selected STARTS---------------------------//
CATBoolean MRFTyreDepthAnsysCmd::OnBaldSurfaceSelectorListSelected(void * data)
{
	if (!!_pDialogAgentForBaldSurface)
		_pDialogAgentForBaldSurface->InitializeAcquisition();

	this->_ActiveListSelected = activeSelection::BaldSurface;

	if (NULL != _pHSO && 0 == _pHSO->IsMember(_pPathElementForBaldSurface))
	{
		_pHSO->Empty();
		_pHSO->AddElement(_pPathElementForBaldSurface);
		if (NULL != _pPathElementForAxis)
		{
			_pHSO->AddElement(_pPathElementForAxis);
		}
	}

	CATUnicodeString strString = "Select Source Surface";
	if (!!_pMRFTyreDepthAnsysCmdDlg)
	{
		_pMRFTyreDepthAnsysCmdDlg->SetStatusBarText(strString);
		ClearAllSelections();

		CATDlgSelectorList* pBaldSurfSelector = NULL;
		pBaldSurfSelector = _pMRFTyreDepthAnsysCmdDlg->GetSelectorListBaldSurf();
		if (NULL != pBaldSurfSelector)
		{
			_pMRFTyreDepthAnsysCmdDlg->SetFocusOnSelectorList(pBaldSurfSelector);
		}
	}
	return TRUE;
}

//---------------------Function to be called when source surface selected inorder to retrieve the selected surafce and store in a global variable STARTS---------------------------//
CATBoolean MRFTyreDepthAnsysCmd::OnSourceSurfaceSelected(void * data)
{
	if (!!_pPathElementAgentForSurface)
	{
		CATUnicodeString surfaceAliasName;
		_pPathElementForSourceSurface = _pPathElementAgentForSurface->GetValue();

		if (!!_pPathElementForSourceSurface)
		{
			if (NULL != _pHSO && 0 == _pHSO->IsMember(_pPathElementForSourceSurface))
			{
				_pHSO->Empty();
				_pHSO->AddElement(_pPathElementForSourceSurface);
			}

			if (!!_pMRFTyreDepthAnsysCmdDlg)
			{
				CATBaseUnknown* pSelectedSurface = _pPathElementForSourceSurface->CurrentElement(); // No need to release the returned object
				if (!!pSelectedSurface)
				{
					_spSourceSurface = pSelectedSurface;

					CATIAlias_var pAliasONSurface(_spSourceSurface);
					if (!!pAliasONSurface)
					{
						surfaceAliasName = pAliasONSurface->GetAlias();
					}
				}
			}
			_pMRFTyreDepthAnsysCmdDlg->SetSelectorListSourceSurf(surfaceAliasName);
			CATDlgSelectorList* pBaldSurfSelector = _pMRFTyreDepthAnsysCmdDlg->GetSelectorListBaldSurf();
			if (NULL != pBaldSurfSelector)
			{
				_pMRFTyreDepthAnsysCmdDlg->SetFocusOnSelectorList(pBaldSurfSelector);
				_bRunCompute = CATTrue;
				_pMRFTyreDepthAnsysCmdDlg->GetProgress()->SetVisibility(CATDlgHide);
			}
		}
		_pPathElementAgentForSurface->InitializeAcquisition();
	}
	return TRUE;
}
//---------------------Function to be called when source surface selected inorder to retrieve the selected surafce and store in a global variable ENDS---------------------------//

//---------------------Function to be called when bald surface selected inorder to retrieve the selected surafce and store in a global variable STARTS---------------------------//
CATBoolean MRFTyreDepthAnsysCmd::OnBaldSurfaceSelected(void * data)
{
	if (!!_pPathElementAgentForSurface)
	{
		CATUnicodeString surfaceAliasName;
		_pPathElementForBaldSurface = _pPathElementAgentForSurface->GetValue();

		if (!!_pPathElementForBaldSurface)
		{
			if (NULL != _pHSO && 0 == _pHSO->IsMember(_pPathElementForBaldSurface))
			{
				_pHSO->Empty();
				_pHSO->AddElement(_pPathElementForBaldSurface);
			}

			if (!!_pMRFTyreDepthAnsysCmdDlg)
			{
				CATBaseUnknown* pSelectedSurface = _pPathElementForBaldSurface->CurrentElement(); // No need to release the returned object
				if (pSelectedSurface)
				{
					_spBaldSurface = pSelectedSurface;

					CATIAlias_var pAliasONSurface(_spBaldSurface);
					if (!!pAliasONSurface)
					{
						surfaceAliasName = pAliasONSurface->GetAlias();
					}
				}
			}
			_pMRFTyreDepthAnsysCmdDlg->SetSelectorListBaldSurf(surfaceAliasName);

			if (NULL_var != _spBaldSurface && NULL != _pComputePointDistance)
			{
				_pComputePointDistance->CreateTyreAxis(_spBaldSurface, _pEditor, _pPathElementForAxis);
				_pComputePointDistance->CreateIntersectionCurve(_spBaldSurface);
				_pComputePointDistance->CreateArrowToRepresentTyreDirection(_pISO);
				_bRunCompute = CATTrue;
				if (NULL != _pHSO && 0 == _pHSO->IsMember(_pPathElementForAxis))
				{
					_pHSO->Empty();
					_pHSO->AddElement(_pPathElementForAxis);
				}
				_pMRFTyreDepthAnsysCmdDlg->GetProgress()->SetVisibility(CATDlgHide);
			}
		}
		_pPathElementAgentForSurface->InitializeAcquisition();
	}
	return TRUE;
}
//---------------------Function to be called when bald surface selected inorder to retrieve the selected surafce and store in a global variable ENDS---------------------------//

//---------------------Function opens file browser to save generated report as text file when Ok Button clicked STARTS---------------------------//
void MRFTyreDepthAnsysCmd::OnOK(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	if (_bRunCompute && NULL != _pComputePointDistance)
	{
		_pComputePointDistance->SetProgressDialog(_pMRFTyreDepthAnsysCmdDlg->GetProgress());
		ComputeDepth();
	}
		

	_pFileDialog = new CATDlgFile(_pMRFTyreDepthAnsysCmdDlg, "SaveFile", CATDlgWndModal | CATDlgFileSave);
	if (NULL == _pFileDialog)
		return;

	AddAnalyseNotificationCB(_pFileDialog, _pFileDialog->GetDiaOKNotification(), (CATCommandMethod)& MRFTyreDepthAnsysCmd::OpenFileSelectionBrowser, NULL);

	CATUnicodeString nameExtension = CATUnicodeString("Text File (*.txt)");
	CATString        filterExtension = CATString("*.txt");

	_pFileDialog->SetFilterStrings(&nameExtension, &filterExtension, 1);
	_pFileDialog->SetVisibility(CATDlgShow);

	return;
}
//---------------------Function opens file browser to save generated report as text file when Ok Button clicked ENDS---------------------------//

//---------------------Function to destroy command when window close button or cancel button clicked STARTS---------------------------//
void MRFTyreDepthAnsysCmd::OnClose(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	if (!!_pMRFTyreDepthAnsysCmdDlg)
		_pMRFTyreDepthAnsysCmdDlg->SetVisibility(CATDlgHide);

	RequestDelayedDestruction();

	//_pMRFTyreDepthAnsysCmdDlg->RequestDelayedDestruction();
}
