//---------------------Function to set filter for Surafce selection type STARTS---------------------------//
CATListOfCATString MRFTyreDepthAnsysCmd::GetSurfaceSelectorTypes()
{
	CATListOfCATString ListSurfaces;
	ListSurfaces.Append("CATI3DGeometricalElement");

	return ListSurfaces;
}
//---------------------Function to set filter for Surafce selection type ENDS---------------------------//

//---------------------Function to clear existing selection of selecvtor list in UI STARTS---------------------------//
void MRFTyreDepthAnsysCmd::ClearAllSelections()
{
	if (!!_pMRFTyreDepthAnsysCmdDlg)
	{
		_pMRFTyreDepthAnsysCmdDlg->GetSelectorListSourceSurf()->ClearSelect();
		_pMRFTyreDepthAnsysCmdDlg->GetSelectorListBaldSurf()->ClearSelect();
	}
}
//---------------------Function to clear existing selection of selecvtor list in UI ENDS---------------------------//

//---------------------Function to open file selection browser to save report as a text file STARTS---------------------------//
void MRFTyreDepthAnsysCmd::OpenFileSelectionBrowser(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	CATUnicodeString fileName;
	_pFileDialog->GetSelection(fileName);

	SaveDepthAnsysReportAsTxtFile(fileName);

	return;
}
//---------------------Function to open file selection browser to save report as a text file ENDS---------------------------//

//---------------------Function to save report as a text file STARTS---------------------------//
void MRFTyreDepthAnsysCmd::SaveDepthAnsysReportAsTxtFile(CATUnicodeString filePath)
{
	if (NULL != _pComputePointDistance)
		_pComputePointDistance->GenerateReport(filePath);

	if (_pFileDialog != NULL)
		_pFileDialog->RequestDelayedDestruction(); _pFileDialog = NULL;
}
//---------------------Function to save report as a text file ENDS---------------------------//

//---------------------Function to Compute Depth STARTS---------------------------//
void MRFTyreDepthAnsysCmd::ComputeDepth()
{
	CATDlgSpinner* pOnSpinnerLateral = _pMRFTyreDepthAnsysCmdDlg->GetEditorGridSpacingLateral();
	CATDlgSpinner* pOnSpinnerCircumf = _pMRFTyreDepthAnsysCmdDlg->GetEditorGridSpacingCircumf();

	double spinnerLateralValue = 0, spinnerCircumfSegments = 0;
	if (pOnSpinnerLateral != NULL)
		spinnerLateralValue = pOnSpinnerLateral->GetValue();

	if (pOnSpinnerCircumf != NULL)
		spinnerCircumfSegments = pOnSpinnerCircumf->GetValue();

	if (!!_spSourceSurface && !!_spBaldSurface && NULL != _pComputePointDistance)
		_pComputePointDistance->CreatePointsList(spinnerLateralValue, spinnerCircumfSegments, _spSourceSurface, _spBaldSurface);

	_bRunCompute = CATFalse;

}
//---------------------Function to Compute Depth ENDS---------------------------//

//---------------------Function to reverse the Tyre Direction and set the arrow representation in UI when reverse TyreDiorection Push button clicked in UI STARTS---------------------------//
void MRFTyreDepthAnsysCmd::OnPushButtonReverseDirectionClicked(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	if (NULL != _pComputePointDistance)
	{
		_pComputePointDistance->OnPushBttnReverseTyreDirectClicked();
		_pComputePointDistance->CreateArrowToRepresentTyreDirection(_pISO);
		_bRunCompute = CATTrue;
		_pMRFTyreDepthAnsysCmdDlg->GetProgress()->SetVisibility(CATDlgHide);
		if (NULL != _pHSO)
		{
			_pHSO->Empty();
			if (!!_pPathElementForAxis)
				_pHSO->AddElement(_pPathElementForAxis);
		}
	}
}
//---------------------Function to reverse the Tyre Direction and set the arrow representation in UI when reverse TyreDiorection Push button clicked in UI ENDS---------------------------//


//---------------------Function to Disable or Enable Compute Push button  STARTS---------------------------//
void MRFTyreDepthAnsysCmd::ResetValues(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	if (NULL != _pComputePointDistance)
	{
		ClearAllSelections();
		_bRunCompute = CATTrue;
		_pMRFTyreDepthAnsysCmdDlg->GetProgress()->SetVisibility(CATDlgHide);
		_pComputePointDistance->Remove3DBagRepFromViewer();
		_pComputePointDistance->ResetSetDataArrayToGenerateReport();
		if (NULL != _pHSO)
		{
			_pHSO->Empty();
			if (!!_pPathElementForAxis)
				_pHSO->AddElement(_pPathElementForAxis);
		}
	}
}
//---------------------Function to Disable or Enable Compute Push button  ENDs---------------------------//

//---------------------Function to be called when right click operation is performed on Selector List to CLear List STARTS---------------------------//
void MRFTyreDepthAnsysCmd::OnContextMenuSourceSurfaceSelected(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	CATString SelectorListIdentifier = (char*)iUsefulData;

	if (SelectorListIdentifier == "FromSourceSurfaceSelectorList")
		this->_ActiveListSelected = activeSelection::SourceSurface;
	else if (SelectorListIdentifier == "FromBaldSurfaceSelectorList")
		this->_ActiveListSelected = activeSelection::BaldSurface;

	CATDlgContextualMenu * pCtxMenuRefSurface = NULL;
	if (this->_ActiveListSelected == activeSelection::SourceSurface)
		pCtxMenuRefSurface = _pMRFTyreDepthAnsysCmdDlg->GetCustomContextualMenuOfSelectorListSourceSurface();
	else if (this->_ActiveListSelected == activeSelection::BaldSurface)
		pCtxMenuRefSurface = _pMRFTyreDepthAnsysCmdDlg->GetCustomContextualMenuOfSelectorListBaldSurface();

	if (NULL != pCtxMenuRefSurface)
	{
		CATDlgPushItem * pBtnClrSelSurface = new CATDlgPushItem(pCtxMenuRefSurface, CATString("Clear Selection"));
		if (NULL != pBtnClrSelSurface)
		{
			CATUnicodeString  strClearSelection = "Clear Selection";
			pBtnClrSelSurface->SetTitle(strClearSelection);
			pBtnClrSelSurface->SetIconName("I_ClearSelection1");
			AddAnalyseNotificationCB(pBtnClrSelSurface, pBtnClrSelSurface->GetMenuIActivateNotification(), (CATCommandMethod)& MRFTyreDepthAnsysCmd::OnCtxMenuClearRefSurface, "ClearSelection");
		}
	}
}
//---------------------Function to be called when right click operation is performed on Selector List to CLear List ENDS---------------------------//

//---------------------Function to be called when Clear List is Selected from contextual menu inorder to clear the existing selection of Selector list STARTS---------------------------//
void MRFTyreDepthAnsysCmd::OnCtxMenuClearRefSurface(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	char * pstrAction = (char *)iUsefulData;
	CATString strAction(pstrAction);

	CATDlgSelectorList* pSelectorListSourceSurface = NULL;

	if (0 == strAction.Compare("ClearSelection"))
	{
		if (this->_ActiveListSelected == activeSelection::SourceSurface)
		{
			if (NULL != _pHSO && NULL != _pPathElementForSourceSurface && 0 != _pHSO->IsMember(_pPathElementForSourceSurface))
			{
				_pHSO->RemoveElement(_pPathElementForSourceSurface);
			}
			_pPathElementForSourceSurface = NULL;
			_spSourceSurface = NULL_var;
			pSelectorListSourceSurface = _pMRFTyreDepthAnsysCmdDlg->GetSelectorListSourceSurf();
		}
		else if (this->_ActiveListSelected == activeSelection::BaldSurface)
		{
			if (NULL != _pHSO && NULL != _pPathElementForBaldSurface && 0 != _pHSO->IsMember(_pPathElementForBaldSurface))
			{
				_pHSO->RemoveElement(_pPathElementForBaldSurface);
			}
			if (NULL != _pHSO && NULL != _pPathElementForAxis && 0 != _pHSO->IsMember(_pPathElementForAxis))
			{
				_pHSO->RemoveElement(_pPathElementForAxis);
			}
			_pPathElementForAxis = NULL;
			_pPathElementForBaldSurface = NULL;
			_spBaldSurface = NULL_var;
			pSelectorListSourceSurface = _pMRFTyreDepthAnsysCmdDlg->GetSelectorListBaldSurf();
		}

		if (pSelectorListSourceSurface)
		{
			ClearAllSelections();
			pSelectorListSourceSurface->ClearSelect();
			pSelectorListSourceSurface->ClearLine();
			pSelectorListSourceSurface->SetLine("No Selection");
			_pMRFTyreDepthAnsysCmdDlg->SetFocusOnSelectorList(pSelectorListSourceSurface);
		}
	}
}
//---------------------Function to be called when Clear List is Selected from contextual menu inorder to clear the existing selection of Selector list ENDS---------------------------//

void MRFTyreDepthAnsysCmd::DisplayPreview(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	if (!!_pMRFTyreDepthAnsysCmdDlg && !!_pComputePointDistance)
	{
		CATDlgCheckButton* pCheckButtonPreview = _pMRFTyreDepthAnsysCmdDlg->GetCheckButtonPreview();
		if (pCheckButtonPreview)
		{
			if (CATDlgCheck == pCheckButtonPreview->GetState())
			{
				_pComputePointDistance->SetPreview(CATTrue);
			}
			else
				_pComputePointDistance->SetPreview(CATFalse);
			ResetValues(ipCommand, ipNotification, iUsefulData);
		}
	}
}


